import React, { useState, useEffect } from 'react';
import { messagesAPI } from '../../utils/api';
import './MessageSender.css';

const MessageSender = ({ 
  groupId, 
  onMessageSent, 
  currentUser,
  replyTo = null,
  onReplyCancel = null 
}) => {
  console.log('🔍 MessageSender props:', { groupId, onMessageSent, currentUser, replyTo });

  const [content, setContent] = useState('');
  const [recipientId, setRecipientId] = useState('');
  const [secondaryRecipientId, setSecondaryRecipientId] = useState('');
  const [recipients, setRecipients] = useState([]);
  const [assignmentInfo, setAssignmentInfo] = useState(null);
  const [loading, setLoading] = useState(false);
  const [loadingRecipients, setLoadingRecipients] = useState(false);
  const [showSecondaryOption, setShowSecondaryOption] = useState(false);

  // 📋 Load available recipients
  useEffect(() => {
    if (groupId) {
      loadRecipients();
    }
  }, [groupId]);

  // 🔍 Load assignment info when recipient is selected
  useEffect(() => {
    if (recipientId && recipientId !== '') {
      loadAssignmentInfo();
    } else {
      setAssignmentInfo(null);
      setSecondaryRecipientId('');
      setShowSecondaryOption(false);
    }
  }, [recipientId]);

  const loadRecipients = async () => {
    setLoadingRecipients(true);
    try {
      const data = await messagesAPI.getRecipients(groupId);
      setRecipients(data.recipients || []);
    } catch (error) {
      console.error('Failed to load recipients:', error);
    } finally {
      setLoadingRecipients(false);
    }
  };

  const loadAssignmentInfo = async () => {
    try {
      const info = await messagesAPI.getAssignmentInfo(groupId, recipientId);
      setAssignmentInfo(info);
      setShowSecondaryOption(info.isAssigned && info.secondaryUsers.length > 0);
    } catch (error) {
      console.error('Failed to load assignment info:', error);
      setAssignmentInfo(null);
      setShowSecondaryOption(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      // 🔒 CORE RULE: Validate recipient selection
      if (!recipientId) {
        alert('Please select a recipient before sending message.');
        return;
      }

      if (!content || !content.trim()) {
        alert('Please enter a message.');
        return;
      }

      console.log('📤 Sending message:', { recipientId, secondaryRecipientId, content: content.trim() });

      setLoading(true);

      const messageData = {
        content: content.trim(),
        recipient_id: parseInt(recipientId),
        secondary_recipient_id: secondaryRecipientId ? parseInt(secondaryRecipientId) : null,
        reply_to_id: replyTo?.id || null
      };

      const response = await messagesAPI.sendMessage(groupId, messageData);

      // 🎯 Reset form
      setContent('');
      setRecipientId('');
      setSecondaryRecipientId('');
      setShowSecondaryOption(false);
      setAssignmentInfo(null);

      // 🔄 Notify parent
      if (onMessageSent) {
        onMessageSent(response.message);
      }

      // 🔄 Cancel reply if active
      if (onReplyCancel) {
        onReplyCancel();
      }

    } catch (error) {
      console.error('❌ Message send error:', error);
      alert(error?.error || 'Failed to send message');
    } finally {
      setLoading(false);
    }
  };

  const handleReplyCancel = () => {
    if (onReplyCancel) {
      onReplyCancel();
    }
  };

  return (
    <div className="message-sender">
      {/* 📝 Reply To Indicator */}
      {replyTo && (
        <div className="reply-to-indicator">
          <div className="reply-info">
            <span className="reply-label">Replying to:</span>
            <span className="reply-content">
              {replyTo.content?.substring(0, 50)}{replyTo.content?.length > 50 ? '...' : ''}
            </span>
            <span className="reply-author">- {replyTo.sender_name}</span>
          </div>
          <button type="button" className="reply-cancel" onClick={handleReplyCancel}>
            ✕
          </button>
        </div>
      )}

      <form onSubmit={handleSubmit} className="message-form">
        {/* 👥 Recipient Selection */}
        <div className="recipient-section">
          <label className="form-label required">
            📧 To <span className="required-star">*</span>
          </label>
          <select
            className="form-control recipient-select"
            value={recipientId}
            onChange={(e) => setRecipientId(e.target.value)}
            required
            disabled={loadingRecipients}
          >
            <option value="">Select recipient *</option>
            {loadingRecipients ? (
              <option disabled>Loading recipients...</option>
            ) : (
              recipients.map((recipient) => (
                <option key={recipient.user_id} value={recipient.user_id}>
                  {recipient.full_name} ({recipient.role || recipient.crm_role})
                </option>
              ))
            )}
          </select>
        </div>

        {/* 🔗 Secondary Recipient (Manager) */}
        {showSecondaryOption && assignmentInfo?.secondaryUsers?.length > 0 && (
          <div className="secondary-recipient-section">
            <label className="form-label">
              🔗 Also notify via (optional)
            </label>
            <select
              className="form-control secondary-recipient-select"
              value={secondaryRecipientId}
              onChange={(e) => setSecondaryRecipientId(e.target.value)}
            >
              <option value="">Optional: Route via manager</option>
              {assignmentInfo.secondaryUsers.map((user) => (
                <option key={user.id} value={user.id}>
                  {user.full_name} ({user.role}) - Manager
                </option>
              ))}
            </select>
            <div className="secondary-hint">
              💡 This will also send the message to the manager
            </div>
          </div>
        )}

        {/* ✍️ Message Content */}
        <div className="message-content-section">
          <label className="form-label">
            ✍️ Message <span className="required-star">*</span>
          </label>
          <textarea
            className="form-control message-textarea"
            value={content}
            onChange={(e) => setContent(e.target.value)}
            placeholder="Type your message here..."
            rows={3}
            required
          />
        </div>

        {/* 🚀 Send Button */}
        <div className="send-section">
          <button
            type="submit"
            className="btn btn-primary send-button"
            disabled={loading || !recipientId || !content.trim()}
          >
            {loading ? (
              <>
                <span className="loading-spinner"></span>
                Sending...
              </>
            ) : (
              <>
                📤 Send Message
              </>
            )}
          </button>

          {/* 📊 Status Info */}
          {recipientId && (
            <div className="message-status">
              {assignmentInfo?.isAssigned ? (
                <span className="status-info assigned">
                  🔗 Recipient has manager assignment
                </span>
              ) : (
                <span className="status-info direct">
                  ✅ Direct message to recipient
                </span>
              )}
            </div>
          )}
        </div>
      </form>
    </div>
  );
};

export default MessageSender;
